import sys

class Solution:
	def schedule(self, tasks: list[list[int]]) -> list[tuple[int, int]]:
		sorted_tasks = sorted(tasks, key=lambda x: x[0]);
		result = [];
		end_time = -sys.maxsize;
		for task in sorted_tasks:
			if task[0] >= end_time:
				result.append((task[0], task[0] + task[1]));
				end_time = task[0] + task[1];
		return result;

if __name__ == '__main__':
	tasks = [[1, 10], [2, 5], [3, 8]];
	sol = Solution();
	print(sol.schedule(tasks));

