#include <iostream>

using namespace std;

void solve(vector<int>& tasks, vector<pair<int, int>>& result) {
	sort(tasks.begin(), tasks.end());
	int end_time = -2147483648;
	for (int i = 0; i < tasks.size(); i++) {
		if (tasks[i] >= end_time) {
			result.push_back(make_pair(tasks[i], tasks[i] + 1));
			end_time = tasks[i] + 1;
		}
	}
}

int main() {
	vector<int> tasks = {1, 2, 3};
	vector<pair<int, int>> result;
	solve(tasks, result);
	for (auto task : result) {
		cout << task.first << ' ' << task.second << endl;
	}
	return 0;
}
